// src/App.js
import React from 'react';
import { BrowserRouter as Router, Route } from 'react-router-dom';
import Welcome from './welcome';
import Login from './Login';

const App = () => {
  return (
    <Router>
        <Route path="/login" component={Login} />
        <Route path="/" component={Welcome} />

    </Router>
  );
};

export default App;
